// Define my message type
enum Message {
  DoWork,
  Shutdown,
}
// Actor struct with inbox
struct MyActor { rx: Receiver<Message> }
impl MyActor {
  async fn run(&self) {
    loop {
      match self.rx.recv().await {
        Some(msg) => match msg {
          Message::DoWork => println!("Doing work...")
          Message::Shutdown => break,
        },
        None => break, // Channel closed
      }
    }
  }
}
